static void pcibase_realize(PCIDevice *pdev, Error **errp)
{
    PCIBaseState *s = PCIBASE_DEVICE(pdev);
    uint8_t *pci_conf = pdev->config;
    int i;

    pci_config_set_interrupt_pin(pci_conf, 1);
    uint16_t dev_id = pci_get_word(pci_conf + PCI_DEVICE_ID);
    if (dev_id == 0x0634)
    { /* MF634: driver expects BAR indices 0,2,3 */
        s->board_id = BOARD_MF634;
        s->num_bars = 3;
        s->bar_info[0] = (BARInfo){.index = 0, .type = BAR_TYPE_MMIO, .size = 0x1000, .name = "bar0"};
        s->bar_info[1] = (BARInfo){.index = 2, .type = BAR_TYPE_MMIO, .size = 0x1000, .name = "bar2"};
        s->bar_info[2] = (BARInfo){.index = 3, .type = BAR_TYPE_MMIO, .size = 0x1000, .name = "bar3"};
    }
    else if (dev_id == 0x0624)
    { /* MF624: driver expects BAR indices 0,2,4 */
        s->board_id = BOARD_MF624;
        s->num_bars = 3;
        s->bar_info[0] = (BARInfo){.index = 0, .type = BAR_TYPE_MMIO, .size = 0x1000, .name = "bar0"};
        s->bar_info[1] = (BARInfo){.index = 2, .type = BAR_TYPE_MMIO, .size = 0x1000, .name = "bar2"};
        s->bar_info[2] = (BARInfo){.index = 4, .type = BAR_TYPE_MMIO, .size = 0x1000, .name = "bar4"};
    }
    else
    { /* 默认兼容性：注册 0,1,2（老行为）*/
        s->board_id = BOARD_MF634;
        s->num_bars = 3;
        s->bar_info[0] = (BARInfo){.index = 0, .type = BAR_TYPE_MMIO, .size = 0x1000, .name = "bar0"};
        s->bar_info[1] = (BARInfo){.index = 1, .type = BAR_TYPE_MMIO, .size = 0x1000, .name = "bar1"};
        s->bar_info[2] = (BARInfo){.index = 2, .type = BAR_TYPE_MMIO, .size = 0x1000, .name = "bar2"};
    }

    for (i = 0; i < s->num_bars; i++) {
        pcibase_register_bar(pdev, s, &s->bar_info[i], errp);
    }

    pcibase_dma_device_realize(pdev, errp);

    s->has_msi = false;
    s->has_msix = false;

    s->mmio_backing = NULL;
    s->mmio_backing_size = 0;

    qemu_log_mask(LOG_UNIMP, "[%s] device realized\n", TYPE_PCIBASE_DEVICE);
}
